local G = DYCLegendary local require = G.DYCModRequire local dlc = G.dlc require( "stategraphs/SGdyc_spear_trap" ) local DYCMakePlacer = require( "dyc_makeplacer" ) local assets = {Asset( "ANIM" , "anim/dyc_spear_trap.zip" ), } local prefabs = {} local RADIUS = 1.4 local TRAP_HEALTH = 0x96 local NO_TAG = { "spear_trap" , "player" , "chester" , "structure" , "wall" } local function CanImpale(inst, ent) return not ent.components.follower or ent.components.follower.leader ~= GetPlayer() end local function Impale(inst) local pt = Point(inst.Transform:GetWorldPosition()) local ents = TheSim:FindEntities(pt.x, pt.y, pt.z, RADIUS * 0x5, nil, NO_TAG) for i, ent in ipairs(ents) do if inst:IsNear(ent, RADIUS + (ent.Physics and ent.Physics:GetRadius() or 0x0)) and ent.components.health and ent.components.combat and CanImpale(inst, ent) then inst.components.combat:DoAttack(ent) end end end local function setextendeddata(inst, extended) if extended then inst.extended = true inst:RemoveTag( "fireimmune" ) if inst.components.burnable then inst.components.burnable.disabled = nil end inst.components.health.vulnerabletoheatdamage = true inst.Physics:SetActive(true) inst.components.activatable.inactive = true inst.components.health:SetInvincible(false) else inst.extended = nil inst:AddTag( "fireimmune" ) if inst.components.burnable then inst.components.burnable.disabled = true end inst.components.health.vulnerabletoheatdamage = false inst.Physics:SetActive(false) inst.components.activatable.inactive = false inst.components.health:SetInvincible(true) end end local function onsave(inst, data) if inst.extended then data.extended = true end end local function onload(inst, data) if data then if data.extended then inst.sg:GoToState( "extended" ) end end inst.workleft = inst.components.workable.workleft end local function disarm(inst, doer) local pt = Point(inst.Transform:GetWorldPosition()) inst.components.lootdropper:SpawnLootPrefab( "blowdart_pipe" , pt) end local function OnHammered(inst, worker) if inst.isBurnt then inst.components.lootdropper:SpawnLootPrefab( "charcoal" ) elseif inst.isBroken then inst.components.lootdropper:SpawnLootPrefab( "twigs" ) else inst.components.lootdropper:SpawnLootPrefab( "log" ) end SpawnPrefab( "collapse_small" ).Transform:SetPosition(inst.Transform:GetWorldPosition()) inst.SoundEmitter:PlaySound( "dontstarve/common/destroy_wood" ) inst:Remove() end local function OnKilled(inst) inst:PushEvent( "dead" ) local debris = SpawnPrefab( "dyc_spear_trap_broken" ) debris.AnimState:PlayAnimation( "breaking" ) debris.AnimState:PushAnimation( "broken" , true) debris.Transform:SetPosition(inst.Transform:GetWorldPosition()) inst.SoundEmitter:PlaySound( "dontstarve_DLC003/common/traps/speartrap_break" ) if inst.dycTask then inst.dycTask:Cancel() end inst:Remove() end local function burnt(inst) local debris = SpawnPrefab( "dyc_spear_trap_broken" ) debris.isBurnt = true debris.AnimState:PlayAnimation( "burnt" ) debris.Transform:SetPosition(inst.Transform:GetWorldPosition()) if inst.dycTask then inst.dycTask:Cancel() end inst:Remove() end local function OnHit(inst) inst:PushEvent( "hit" ) inst:ResetResetTimer() end local function OnWork(inst, worker, workleft) local hashammer = false if worker.components.inventory then for k, v in pairs(worker.components.inventory.equipslots) do if v.components.tool and v.components.tool:CanDoAction(ACTIONS.HAMMER) then hashammer = true if v.components.finiteuses then v.components.finiteuses:Use( - 0x1) end break end end end if not hashammer then inst.components.workable.destroyed = false inst.components.workable.workleft = inst.workleft else inst.workleft = inst.workleft - 0x1 inst.components.workable.workleft = inst.workleft end OnHit(inst) end local function OnWork2(inst, worker, workleft) local hashammer = false if worker.components.inventory then for k, v in pairs(worker.components.inventory.equipslots) do if v.components.tool and v.components.tool:CanDoAction(ACTIONS.HAMMER) then hashammer = true if v.components.finiteuses then v.components.finiteuses:Use( - 0x1) end break end end end if not hashammer then inst.components.workable.destroyed = false inst.components.workable.workleft = inst.workleft else inst.workleft = inst.workleft - 0x1 inst.components.workable.workleft = inst.workleft end end local function canbeattackedfn(inst) local canbeattacked = true if inst:HasTag( "burnt" ) or inst:HasTag( "dead" ) then canbeattacked = false end return canbeattacked end local function Init(inst) local pos = inst:GetPosition() inst.Transform:SetPosition(math.floor(pos.x) + 0.5, 0x0, math.floor(pos.z) + 0.5) if not inst.extended then inst:PushEvent( "reset" ) end end local function TaskFn(inst) if not inst.detectTimer then inst.detectTimer = 0x0 end if not inst.resetTimer then inst.resetTimer = 0x0 end if not inst.regenTimer then inst.regenTimer = 0x0 end if not inst.extended then inst:ResetResetTimer() inst.detectTimer = inst.detectTimer - FRAMES if inst.detectTimer <= 0x0 then inst.detectTimer = 0.3 local pos = inst:GetPosition() local ents = TheSim:FindEntities(pos.x, pos.y, pos.z, RADIUS * 0x3, nil, NO_TAG) for k, ent in ipairs(ents) do if inst:IsNear(ent, RADIUS - 0.1 + (ent.Physics and ent.Physics:GetRadius() or 0x0)) and ent.components.health and not ent.components.health:IsDead() and ent.components.combat and CanImpale(inst, ent) then inst:PushEvent( "spring" ) break end end end inst.regenTimer = inst.regenTimer - FRAMES if inst.regenTimer <= 0x0 then inst.regenTimer = 0x1 if inst.components.health then inst.components.health:DoDelta(0x5 * TRAP_HEALTH / 0x64, true, nil, true) end end else inst.resetTimer = inst.resetTimer - FRAMES if inst.resetTimer <= 0x0 then inst:PushEvent( "reset" ) end end end local function fn(Sim) local inst = CreateEntity() local trans = inst.entity:AddTransform() local anim = inst.entity:AddAnimState() inst.entity:AddSoundEmitter() MakeObstaclePhysics(inst,.5) inst.Physics:SetActive(false) inst.setextendeddata = setextendeddata local minimap = inst.entity:AddMiniMapEntity() minimap:SetIcon( "minimap_dyc_spear_trap.tex" ) minimap:SetPriority( - 0x1) inst:AddComponent( "combat" ) inst.components.combat:SetOnHit(OnHit) inst.components.combat:SetDefaultDamage(0x96) inst.components.combat.canbeattackedfn = canbeattackedfn inst.Impale = Impale inst:AddComponent( "activatable" ) inst.components.activatable.OnActivate = function() inst:PushEvent( "reset" ) end inst.components.activatable.standingaction = false inst.components.activatable.quickaction = true inst.components.activatable.getverb = function() return "RESETTRAP" end inst.Init = Init inst:ListenForEvent( "death" , OnKilled) inst:ListenForEvent( "onbuilt" , function() inst:Init() end) inst:AddComponent( "health" ) inst.components.health:SetMaxHealth(TRAP_HEALTH) anim:SetBank( "spear_trap" ) anim:SetBuild( "dyc_spear_trap" ) anim:PlayAnimation( "idle_extend" ) inst:AddTag( "spear_trap" ) inst:AddTag( "tree" ) inst:AddTag( "structure" ) inst:AddComponent( "inspectable" ) if dlc >= 0x3 then inst:AddComponent( "shearable" ) inst.onshear = function(inst, shearer) OnKilled(inst) end inst.canshear = function(inst) return inst.extended end end inst:SetStateGraph( "SGdyc_spear_trap" ) MakeSmallBurnable(inst) inst.components.burnable.disabled = true MakeSmallPropagator(inst) inst.components.burnable:SetFXLevel(0x2) inst.components.burnable:SetOnBurntFn(burnt) if inst.components.burnable.MakeDragonflyBait then inst.components.burnable:MakeDragonflyBait(0x1) end inst:AddComponent( "lootdropper" ) inst:AddComponent( "workable" ) inst.components.workable:SetWorkAction(ACTIONS.HAMMER) inst.components.workable:SetWorkLeft(0x3) inst.components.workable:SetOnFinishCallback(OnHammered) inst.components.workable:SetOnWorkCallback(OnWork) inst.workleft = 0x3 inst.OnLoad = onload inst.OnSave = onsave inst.ResetResetTimer = function(inst) inst.resetTimer = 0xf end inst.dycTask = inst:DoPeriodicTask(FRAMES, TaskFn) return inst end local function OnRepaired(inst, doer, repair_item) local repairValue = repair_item.components.repairer.healthrepairvalue * TRAP_HEALTH / 0x4b if repair_item.prefab == "livinglog" then repairValue = TRAP_HEALTH end if inst.components.health then inst.components.health:DoDelta(repairValue, false, nil, true) end if inst.components.health and not inst.components.health:IsHurt() then local trap = SpawnPrefab( "dyc_spear_trap" ) trap.Transform:SetPosition(inst.Transform:GetWorldPosition()) trap:Init() inst:Remove() end end local function debrisfn(Sim) local inst = CreateEntity() local trans = inst.entity:AddTransform() local anim = inst.entity:AddAnimState() inst.entity:AddSoundEmitter() inst:AddTag( "spear_trap" ) inst:AddTag( "tree" ) inst:AddTag( "structure" ) anim:SetBank( "spear_trap" ) anim:SetBuild( "dyc_spear_trap" ) anim:PlayAnimation( "broken" ) inst:AddComponent( "inspectable" ) inst:AddComponent( "lootdropper" ) inst:AddComponent( "workable" ) inst.components.workable:SetWorkAction(ACTIONS.HAMMER) inst.components.workable:SetWorkLeft(0x1) inst.components.workable:SetOnFinishCallback(OnHammered) inst.components.workable:SetOnWorkCallback(OnWork2) inst.workleft = 0x1 inst:AddComponent( "health" ) inst.components.health:SetMaxHealth(TRAP_HEALTH) inst.components.health:SetInvincible(true) inst.components.health:SetVal(0.01) inst:AddComponent( "repairable" ) inst.components.repairable.repairmaterial = "wood" inst.components.repairable.onrepaired = OnRepaired inst.isBroken = true return inst end return Prefab( "common/dyc_spear_trap" , fn, assets, prefabs), Prefab( "common/dyc_spear_trap_broken" , debrisfn, assets, prefabs), DYCMakePlacer( "common/dyc_spear_trap_placer" , "spear_trap" , "dyc_spear_trap" , "idle_extend" , false, false, true) 